// app/page.tsx
import { revalidateTag } from 'next/cache';
import { getAllProducts } from '@/lib/db';

export const dynamic = 'force-dynamic';

async function syncLatestCatalog(formData: FormData) {
  'use server';
  void formData;
  revalidateTag('products', 'max');
}

export default async function Page() {
  const products = await getAllProducts();

  return (
    <main style={{ padding: 24, fontFamily: 'system-ui, sans-serif' }}>
      <h1>Product Catalog</h1>
      <p>Browse the latest catalog data without forcing every request to recompute it.</p>

      <form action={syncLatestCatalog} style={{ margin: '16px 0 24px' }}>
        <button type="submit">Sync latest catalog</button>
      </form>

      <table cellPadding={8} style={{ borderCollapse: 'collapse', minWidth: 420 }}>
        <thead>
          <tr>
            <th align="left">ID</th>
            <th align="left">Name</th>
            <th align="left">Price</th>
          </tr>
        </thead>
        <tbody>
          {products.map((product) => (
            <tr key={product.id}>
              <td>{product.id}</td>
              <td>{product.name}</td>
              <td>${product.price}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </main>
  );
}


